### Load data


::: {.cell}

```{.r .cell-code}
library(cbbplotR)
library(rlang)

# majority of data wrangling done via evdevbyc repo
# see https://github.com/gallochris/evdev-byc/blob/main/data/college-basketball/

all_net_data <- readr::read_csv("byc_net.csv")

conference_summary <- all_net_data |> 
  dplyr::filter(conf %in% c("ACC", "Big 12", "SEC", 
                            "Big East", "Big Ten", "Mountain West")) |> 
  dplyr::mutate(
    conf = dplyr::case_match(conf,
                             "ACC" ~ "ACC - 18 teams",
                             "SEC" ~ "SEC - 16 teams",
                             "Big 12" ~ "Big 12 - 16 teams",
                             "Big Ten" ~ "Big Ten - 18 teams", 
                             "Big East" ~ "Big East - 11 teams",
                             "Mountain West" ~ "Mountain West - 11 teams", 
                             conf ~ conf
    ),
    conf = factor(conf, levels = c("SEC - 16 teams", "Big 12 - 16 teams", 
                                   "Big Ten - 18 teams", "Big East - 11 teams", 
                                   "ACC - 18 teams", "Mountain West - 11 teams"))
  ) |> 
  dplyr::group_by(date, conf) |> 
  dplyr::summarize(
    min_net = min(net, na.rm = TRUE),
    max_net = max(net, na.rm = TRUE),
    min_team = dplyr::first(team[which.min(net)]),
    max_team = dplyr::first(team[which.max(net)]),
    median_net = median(net, na.rm = TRUE),
    .groups = "drop"
  )

last_date_data <- conference_summary |>
  dplyr::filter(date == max(date))


# load cfb data from sportsoddhistory.com 
cfb <- readr::read_csv("cfb-champs.csv") |> 
  dplyr::select(season = Season, date = Date, where =Location, 
                game = ...4, score = ...5, winner = ...6,
                fav = Favorite)
```
