### Geom Ribbon chart


::: {.cell}

```{.r .cell-code}
conf_plot <- ggplot2::ggplot(conference_summary) +
  ggplot2::geom_ribbon(
    ggplot2::aes(x = date, ymin = min_net, ymax = max_net, fill = conf),
    alpha = 0.3
  ) +
  hrbrthemes::theme_ipsum_rc(grid="XY") +
  ggplot2::geom_line(ggplot2::aes(x = date, y = min_net, color = conf), size = 1, linetype = "dashed") +
  ggplot2::geom_line(ggplot2::aes(x = date, y = max_net, color = conf), size = 1, linetype = "dashed") +
  ggplot2::geom_line(
    data = conference_summary,
    ggplot2::aes(x = date, y = median_net, color = conf),
    size = 1.2, 
    linetype = "dotted"
  ) +
  ggplot2::geom_label(
    data = last_date_data,
    ggplot2::aes(x = date, y = min_net, label = min_team),
    hjust = 1, vjust = -0.30,
    size = 4,
    family = "Roboto Condensed",
    label.padding = ggplot2::unit(0.1, "lines"),
    label.size = 0
  ) +
  ggplot2::geom_label(
    data = last_date_data,
    ggplot2::aes(x = date, y = max_net, label = max_team),
    hjust = 1, vjust = 1.7,
    size = 4,
    family = "Roboto Condensed",
    label.padding = ggplot2::unit(0.1, "lines"),
    label.size = 0
  ) +
  ggplot2::scale_y_reverse(breaks = seq(0, 350, by = 50)) + 
  ggplot2::labs(
    title = "NET Ranking Trends by Conference from December 1st to January 16th",
    subtitle = "Tracks 46 days of NET ranking shifts for six conferences.<br>Shows the best and worst-ranked teams today and the median over time.",
    x = "",
    y = "NET",
    color = "Conference",
    caption = "Viz by Chris at Bless your Chart | data via stats.ncaa.org | data through January 16 games"
  ) +
  ggplot2::facet_wrap(
    ~ conf,
    nrow = 3
  ) + 
  ggplot2::coord_flip() +
  ggplot2::coord_cartesian(ylim = c(350, -10)) +  # Expand y-axis limits
  ggplot2::theme(
    axis.text.x = ggplot2::element_text(angle = 75, hjust = 1, face ="bold"),
    axis.title.y = ggplot2::element_text(face = "bold", size = 12),
    legend.position = "none",
    strip.text = ggplot2::element_text(face = "bold"),
    plot.subtitle = ggtext::element_markdown(),
    plot.caption = ggtext::element_markdown(family = "Roboto Condensed")
  )

ggplot2::ggsave(
    "conf_plot.png",
    conf_plot,
    w = 8.75,
    h = 12,
    dpi = 600,
    bg = "white",
    type = 'cairo'
)
```
