```{.r .cell-code}
options(chromote.headless = "new")
cfb_tbl <- cfb |> 
  cbbplotR::gt_cbb_teams(winner, winner, include_name = FALSE) |> 
  dplyr::mutate(winner = 
                  dplyr::if_else(season == 2024, 
                                 "<img src='https://a.espncdn.com/combiner/i?img=/redesign/assets/img/icons/ESPN-icon-football-college.png' style='height: 25px; width: auto; vertical-align: -30%;'>",
                                 winner)) |> 
  dplyr::relocate(season, .after = winner) |> 
  dplyr::relocate(score, .after = winner) |> 
  dplyr::mutate(fav = dplyr::if_else(fav == "Yes", "check", "circle-xmark")) |>  dplyr::mutate(score = dplyr::if_else(is.na(score), "-", score),
                fav = dplyr::if_else(is.na(fav), "-", fav)                                                                               ) |> 
  gt::gt() |> 
  gt::fmt_markdown(winner) |> 
  gtUtils::gt_theme_gtutils() |> 
  gtExtras::gt_merge_stack(col1 = where, col2 = date) |> 
   gt::fmt_icon(
    rows = c(1, 5, 6, 8),
    columns = c(fav),
    fill_color = "#056206",
  ) |> 
   gt::fmt_icon(
    rows = c(2, 3, 4),
    columns = c(fav),
    fill_color = "#ff4c4c",
  ) |> 
  gt::cols_align(align = "right", columns = c(game, season)) |>
   gt::cols_align(align = "left", columns = c(where, winner, score, fav)) |> 
   gtUtils::gt_column_subheaders(
    winner = list(heading = "Champion", subtitle = "Winner"),
    fav = list(heading = "Favorite", subtitle = "Cover?"),
    score = list(heading = "Final", subtitle = "Score"),
    where = list(heading = "Location", subtitle = "Date"),
    season = list(heading = "Season", subtitle = "From Fall"),
    heading_color = "black",
    subtitle_color = "gray"
  ) |> 
  gt::cols_label(
    game = ""
  ) |> 
  gtExtras::gt_add_divider(
    columns = c(where, season),
    sides = "right",
    color = "black"
  ) |> 
    gt::tab_header(
    title = gt::html("National Champonship games with a point spread greater than a touchdown since 1998"),
    subtitle = gt::html(
      "Shows the eight college football championship games since 1998 with a point spread of eight or more points. <br>Ohio State is favored by -8.5 points against Notre Dame on Monday."
    )
  ) |>
  gt::tab_source_note(
    source_note =
      gt::html(
        "<hr>Data via sportsoddshistory.com, theme via {gtUtils}<hr>
        <b>Table by Chris at Bless your chart</b>"
      )
  ) |>
  gt::tab_style(
    locations = gt::cells_source_notes(),
    style = gt::cell_text(
      font = gt::google_font("Signika Negative"),
      size = gt::px(11.5),
      weight = 250
    )
  ) |>
   gt::tab_style(
    style = list(
      gt::cell_text(font = gt::google_font("Signika Negative")
      )
    ),
    locations = gt::cells_body(
      columns = c(where, date, game)
    )
  ) |> 
  gt::tab_style(
    style = list(gt::cell_fill(color = "#C5C5FF")),
    locations = gt::cells_body(columns = c(game), rows = c(7))
  ) |> 
  gt::tab_options(table.width = gt::px(775)) |> 
   gtUtils::gt_border_bars_bottom(c("#636363", "#969696", "#cccccc"))

gtUtils::gt_save_crop(
